import AppKit
import SwiftUI

enum NookIconName: String, CaseIterable {
    case calendar
    case flag
    case tag
    case check
    case plus
    case trash
    case pen
    case copy
    case pin
    case sort
    case gear
    case x
    case arrow
    case clip
    case inbox
    case doc
    case drag
    case clock
    case chevron
    case checkmark
    case sidebarLeft   // « 收起面板（避免与 .x 混淆）
}

struct NookIcon: View {
    let name: NookIconName
    let size: CGFloat

    init(_ name: NookIconName, size: CGFloat = 16) {
        self.name = name
        self.size = size
    }

    var body: some View {
        Image(nsImage: NookIconStore.image(for: name))
            .renderingMode(.template)
            .resizable()
            .scaledToFit()
            .frame(width: size, height: size)
    }
}

private enum NookIconStore {
    private static var cache: [NookIconName: NSImage] = [:]

    static func image(for name: NookIconName) -> NSImage {
        if let image = cache[name] { return image }
        let svg = """
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
        \(body(for: name))
        </svg>
        """
        let image = NSImage(data: Data(svg.utf8)) ?? NSImage(size: NSSize(width: 24, height: 24))
        image.isTemplate = true
        cache[name] = image
        return image
    }

